using System;

namespace Game.NetcodeCore
{
    /// <summary>
    /// Configuration for the lockstep simulation protocol, controlling input delay,
    /// hash verification intervals, and buffer sizes.
    /// </summary>
    public sealed class LockstepConfig
    {
        /// <summary>Number of frames to delay input before applying (default: 2).</summary>
        public int InputDelayFrames = 2;

        /// <summary>Interval in frames between hash verification checks (default: 10).</summary>
        public int HashIntervalFrames = 10;

        /// <summary>Delay in frames before resending unacknowledged commands (default: 5).</summary>
        public int ResendDelayFrames = 5;

        /// <summary>Delay in frames before requesting a resend of missing data (default: 20).</summary>
        public int ResendRequestDelayFrames = 20;

        /// <summary>Maximum number of frames to buffer for command history (default: 256).</summary>
        public int CommandBufferFrames = 256;

        /// <summary>Maximum number of frames to buffer for hash history (default: 256).</summary>
        public int HashBufferFrames = 256;

        /// <summary>
        /// Validates that all configuration values are within acceptable ranges.
        /// </summary>
        /// <exception cref="ArgumentOutOfRangeException">Thrown when any value is out of range.</exception>
        public void Validate()
        {
            if (InputDelayFrames < 0) throw new ArgumentOutOfRangeException(nameof(InputDelayFrames));
            if (HashIntervalFrames <= 0) throw new ArgumentOutOfRangeException(nameof(HashIntervalFrames));
            if (ResendDelayFrames <= 0) throw new ArgumentOutOfRangeException(nameof(ResendDelayFrames));
            if (ResendRequestDelayFrames <= 0) throw new ArgumentOutOfRangeException(nameof(ResendRequestDelayFrames));
            if (CommandBufferFrames <= 0) throw new ArgumentOutOfRangeException(nameof(CommandBufferFrames));
            if (HashBufferFrames <= 0) throw new ArgumentOutOfRangeException(nameof(HashBufferFrames));
        }
    }
}
